/**
 * @summary Get transaction log
 */
export const getGetTransactionLogUrl = (params?: GetTransactionLogParams) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/admin/transactions?${stringifiedParams}`
    : `/api/admin/transactions`;
};

export const getTransactionLog = async (
  params?: GetTransactionLogParams,
  options?: RequestInit,
): Promise<TransactionLog> => {
  return customFetch<TransactionLog>(getGetTransactionLogUrl(params), {
    ...options,
    method: "GET",
  });
};

export const getGetTransactionLogQueryKey = (
  params?: GetTransactionLogParams,
) => {
  return [`/api/admin/transactions`, ...(params ? [params] : [])] as const;
};

